=Create a product listing for this doll outfit image. Image URL: {{$json.body.image_url}}
Details provided: {{$json.body.details || 'No additional details'}}
Doll type: {{$json.body.doll_type || 'Bratz'}}

Generate a luxury product listing in JSON format.

parameters.jsCode:
const raw = $input.item.json.message?.content || $input.item.json.choices?.[0]?.message?.content || '{}';
const cleaned = raw.replace(/```json\n?|```/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{
    json: {
      ...parsed,
      sku: 'SKU-' + Date.now(),
      status: 'draft',
      inventory_quantity: 0,
      images: [{ url: $('Webhook: New Product Image').item.json.body.image_url, alt: parsed.title }],
      created_by: 'ai'
    }
  }];
} catch(e) {
  return [{ json: { error: 'Parse failed', raw } }];
}
